// ─── cycling lines: name then role, then repeat ──────────────────────────
// Each "phase": type the text, pause, erase, move to next
const CYCLE = [
  { text: "Muhammed Fayiz CH",   color: "#4D4D4D" },
  { text: "Full-Stack MERN Developer", color: "#e8652a" },
];

function HeroCycle() {
  const [phaseIdx, setPhaseIdx] = useState(0);
  const [displayed, setDisplayed] = useState("");
  const [mode, setMode]   = useState<"typing"|"pausing"|"erasing">("typing");
  const charRef = useRef(0);

  useEffect(() => {
    const target = CYCLE[phaseIdx].text;

    if (mode === "typing") {
      if (charRef.current < target.length) {
        const t = setTimeout(() => {
          charRef.current += 1;
          setDisplayed(target.slice(0, charRef.current));
        }, 72);
        return () => clearTimeout(t);
      } else {
        // fully typed → pause
        const t = setTimeout(() => setMode("erasing"), 2200);
        return () => clearTimeout(t);
      }
    }

    if (mode === "erasing") {
      if (charRef.current > 0) {
        const t = setTimeout(() => {
          charRef.current -= 1;
          setDisplayed(target.slice(0, charRef.current));
        }, 38);
        return () => clearTimeout(t);
      } else {
        // fully erased → switch phase
        setPhaseIdx(i => (i + 1) % CYCLE.length);
        setMode("typing");
      }
    }
  }, [displayed, mode, phaseIdx]);

  const current = CYCLE[phaseIdx];

  return (
    <span
      style={{
        fontFamily: "'Press Start 2P', monospace",
        fontSize: "clamp(20px, 2.2vw, 28px)",
        color: current.color,
        lineHeight: 1.7,
        letterSpacing: "0.01em",
        display: "inline-block",
        /* fixed min-height so the line never collapses between phases */
        minHeight: "2.4em",
      }}
      aria-label="Muhammed Fayiz CH — Full-Stack Developer"
    >
      {displayed}
      <span
        style={{
          display: "inline-block",
          width: "2px",
          height: "0.8em",
          background: current.color,
          marginLeft: "3px",
          verticalAlign: "middle",
          animation: "blink 1s step-end infinite",
        }}
      />
    </span>
  );
}

// ─── reveal on scroll ────────────────────────────────────────────────────
function Reveal({ children, delay = 0 }: { children: React.ReactNode; delay?: number }) {
  const ref = useRef<HTMLDivElement>(null);
  const [v, setV] = useState(false);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const ob = new IntersectionObserver(([e]) => { if (e.isIntersecting) setV(true); }, { threshold: 0.1 });
    ob.observe(el); return () => ob.disconnect();
  }, []);
  return (
    <div ref={ref} style={{ opacity: v?1:0, transform: v?"translateY(0)":"translateY(22px)", transition:`opacity 0.65s ease ${delay}s, transform 0.65s ease ${delay}s` }}>
      {children}
    </div>
  );
}

